/**
 * speculative-sampling.test.ts — verify both speculative-decode axes.
 *
 * Axis 1 (early-exit): the `2·τ ≤ γ` gate admits the right exit layer and the
 *   decision is variable-length in the margin.
 * Axis 2 (token-level): the accept/verify loop is LOSSLESS — over many draws its
 *   empirical output distribution matches sampling the target directly.
 */

import { describe, expect, it } from 'vitest';
import {
  admitsEarlyExit,
  pickExitLayer,
  topTwoMargin,
  verifyDraftSpan,
  type DraftStep,
  type ExitLayerCalibration,
} from './speculative-sampling';

// Deterministic uniform stream (splitmix-ish), no Math.random in tests.
function uniforms(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (s + 0x9e3779b9) >>> 0;
    let z = s;
    z = Math.imul(z ^ (z >>> 16), 0x21f0aaad) >>> 0;
    z = Math.imul(z ^ (z >>> 15), 0x735a2d97) >>> 0;
    z = (z ^ (z >>> 15)) >>> 0;
    return z / 0x100000000;
  };
}

describe('axis 1: conformal layer early-exit', () => {
  it('topTwoMargin returns the runner-up gap', () => {
    expect(topTwoMargin([1, 5, 3])).toBeCloseTo(2); // 5 − 3
    expect(topTwoMargin([7])).toBe(0); // degenerate
    expect(topTwoMargin([])).toBe(0);
  });

  it('admits exit iff 2·τ ≤ γ (the energy bound, not a free knob)', () => {
    expect(admitsEarlyExit(1.0, 2.0)).toBe(true); // 2·1 = 2 ≤ 2
    expect(admitsEarlyExit(1.01, 2.0)).toBe(false); // 2·1.01 > 2
    expect(admitsEarlyExit(1.0, 0)).toBe(false); // no margin
    expect(admitsEarlyExit(Infinity, 2.0)).toBe(false); // uncertifiable layer
  });

  it('picks the EARLIEST layer clearing the gate', () => {
    const cal: ExitLayerCalibration[] = [
      { layer: 4, tauQ: 0.2, q: 0.99 }, // 0.4 ≤ γ
      { layer: 8, tauQ: 0.1, q: 0.99 }, // also clears, but deeper
      { layer: 2, tauQ: 0.9, q: 0.99 }, // 1.8 > γ → not admitted
    ];
    const d = pickExitLayer(/* gamma */ 1.0, cal);
    expect(d.exitLayer).toBe(4);
    expect(d.certifiedFlipRateLe).toBeCloseTo(0.01); // 1 − q
  });

  it('is variable-length in the margin: easy tokens exit shallower', () => {
    const cal: ExitLayerCalibration[] = [
      { layer: 2, tauQ: 0.5, q: 0.99 },
      { layer: 6, tauQ: 0.1, q: 0.99 },
    ];
    expect(pickExitLayer(2.0, cal).exitLayer).toBe(2); // big margin → shallow
    expect(pickExitLayer(0.5, cal).exitLayer).toBe(6); // small margin → deep
    expect(pickExitLayer(0.1, cal).exitLayer).toBeNull(); // tiny margin → full depth
  });
});

describe('axis 2: lossless token-level accept/verify', () => {
  it('rejects malformed targetDists length', () => {
    const draft: DraftStep[] = [{ token: 0, q: [1] }];
    expect(() => verifyDraftSpan(draft, [[1]], uniforms(1))).toThrow(/draft.length\+1/);
  });

  it('accepts every token when draft == target (and emits a bonus)', () => {
    const dist = [0.25, 0.25, 0.25, 0.25];
    const draft: DraftStep[] = [
      { token: 1, q: dist },
      { token: 3, q: dist },
    ];
    const r = verifyDraftSpan(draft, [dist, dist, dist], uniforms(7));
    expect(r.acceptedTokens).toEqual([1, 3]);
    expect(r.rejectedAt).toBe(2); // == draft.length → full accept
    expect(r.correctedToken).toBeGreaterThanOrEqual(0);
  });

  it('output distribution matches the target (losslessness)', () => {
    // Target p, draft q deliberately mismatched so acceptance + residual both fire.
    const p = [0.1, 0.6, 0.2, 0.1];
    const q = [0.4, 0.2, 0.3, 0.1];
    const rng = uniforms(12345);
    const N = 60000;
    const counts = [0, 0, 0, 0];
    for (let n = 0; n < N; n++) {
      // single-step draft: token sampled from q
      const draftTok = sampleDist(q, rng());
      const r = verifyDraftSpan([{ token: draftTok, q }], [p, p], rng);
      const emitted = r.acceptedTokens.length > 0 ? r.acceptedTokens[0]! : r.correctedToken;
      counts[emitted]!++;
    }
    for (let v = 0; v < p.length; v++) {
      expect(counts[v]! / N).toBeCloseTo(p[v]!, 1); // within ~0.05 of target
    }
  });
});

function sampleDist(dist: readonly number[], u: number): number {
  let acc = 0;
  for (let i = 0; i < dist.length; i++) {
    acc += dist[i]!;
    if (u < acc) return i;
  }
  return dist.length - 1;
}
